import { useEffect, useState } from "react";
import axios from "axios";
import { Bar } from "react-chartjs-2";
import "./AdminDashboard.css";

import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

function AdminDashboard(){

  const [data,setData] = useState({});
  const [recent,setRecent] = useState([]);

  useEffect(()=>{

    axios.get("http://localhost:5000/admindashboard")
    .then(res=>{
      setData(res.data);
      setRecent(res.data.recentPredictions || []);
    })
    .catch(err=>{
      console.log(err);
    });

  },[]);

  const chartData = {
    labels: data.topFactors?.map(item => item._id) || [],
    datasets: [
      {
        label: "Top Factors",
        data: data.topFactors?.map(item => item.count) || [],
        backgroundColor: "#4CAF50"
      }
    ]
  };

  return(

  <div className="dashboard-container">

    {/* Sidebar */}

    <div className="sidebar">

      <h2>Admin</h2>

      <a href="/admindashboard">Dashboard</a>
      <a href="/users">Users</a>
      <a href="/predictions">Predictions</a>
      <a href="/accuracy">Model Accuracy</a>
      <a href="/reports">Reports</a>
      <a href="/">Logout</a>

    </div>


    {/* Main */}

    <div className="main-content">

      <h1>Admin Dashboard</h1>

      {/* Cards */}

      <div className="cards">

        <div className="card">
          <h3>Total Users</h3>
          <p>{data.totalUsers}</p>
        </div>

        <div className="card">
          <h3>Total Predictions</h3>
          <p>{data.totalPredictions}</p>
        </div>

        <div className="card">
          <h3>Model Accuracy</h3>
          <p>{data.modelAccuracy ? data.modelAccuracy*100 : 0}%</p>
        </div>

      </div>


      {/* Chart */}

      <div className="chart-box">

        <h2>Top Factors Used</h2>

        <Bar data={chartData}/>

      </div>


      {/* Recent Predictions */}

      <div className="table-box">

        <h2>Recent Predictions</h2>

        <table>

          <thead>
            <tr>
              <th>Name</th>
              <th>Experience</th>
              <th>Education</th>
              <th>Predicted Salary</th>
            </tr>
          </thead>

          <tbody>

            {recent.map((item,index)=>(
              <tr key={index}>
                <td>{item.name}</td>
                <td>{item.experience}</td>
                <td>{item.education}</td>
                <td>{item.salary}</td>
              </tr>
            ))}

          </tbody>

        </table>

      </div>

    </div>

  </div>

  );
}

export default AdminDashboard;
